{
  "grammar": [
    {
      "pattern": "因為 + reason，所以 + result",
      "structure": ["因為", "reason", "，", "所以", "result"],
      "explanation_en": "Use '因為 (yīnwèi)' to state the reason and '所以 (suǒyǐ)' to state the result. This structure clearly links cause and effect.",
      "title": "因為...所以... (Cause and Effect)",
      "meaning": "Because... therefore...",
      "when_to_use": ["When explaining why you do or don't want something", "When giving a reason for an action or feeling"],
      "when_not_to_use": ["When the reason is obvious from context", "In very casual, short responses where just the reason is enough"],
      "pragmatic_notes": "In Taiwan, this structure is very common in both spoken and written Chinese. It's polite to give a reason before stating your decision, especially when declining an offer.",
      "word_order_notes": "The reason clause always comes first, followed by the result clause. This is the opposite of English, where 'because' can come after the result.",
      "english_contrast": "In English, you can say 'I don't want to eat because I'm full.' In Chinese, the reason must come first: '因為我飽了，所以不想吃。'",
      "korean_contrast": "In Korean, '~기 때문에' is similar but can be placed at the end of the sentence. In Chinese, '因為' must start the reason clause.",
      "negative_examples": [
        {
          "text": "我所以不想吃因為我飽了。",
          "error": "The word order is wrong. '所以' must come before the result, and '因為' must start the reason clause."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我所以不想吃因為我飽了。",
          "error": "Incorrect word order. Use '因為...所以...' structure."
        }
      ],
      "transformation_drills": ["Change '因為我餓了，所以想吃飯。' to a negative reason: '因為我不餓，所以不想吃飯。'"],
      "production_drills": ["Explain why you don't want to go out today using 因為...所以..."],
      "common_error_patterns": ["Placing '所以' before the reason", "Omitting '所以' in a full cause-effect sentence"],
      "repair_feedback": {
        "word_order": "Remember: 因為 + reason + 所以 + result. Don't swap them.",
        "politeness": "Using this structure makes your refusal sound polite and reasoned.",
        "vocabulary": "Use reason words like 太累了, 沒時間, 下雨了."
      }
    },
    {
      "pattern": "為什麼 + question?",
      "structure": ["為什麼", "subject", "verb", "object", "?"],
      "explanation_en": "Use '為什麼 (wèishénme)' to ask 'why' someone wants or doesn't want something. It's a direct question word.",
      "title": "為什麼 (Why)",
      "meaning": "Why?",
      "when_to_use": ["When asking for a reason", "When you want to understand someone's motivation"],
      "when_not_to_use": ["When the reason is already known", "In very formal writing, where '為何' might be preferred"],
      "pragmatic_notes": "In Taiwan, '為什麼' is neutral and can be used in most situations. For very polite inquiries, you can soften it with '請問為什麼...'",
      "word_order_notes": "'為什麼' usually comes at the beginning of the question, before the subject. It can also be placed after the subject for emphasis.",
      "english_contrast": "In English, 'why' can be placed at the end (e.g., 'You did that why?'). In Chinese, '為什麼' must come at the start or after the subject.",
      "korean_contrast": "In Korean, '왜' is placed before the verb. In Chinese, '為什麼' is placed at the beginning of the sentence.",
      "negative_examples": [
        {
          "text": "你為什麼？",
          "error": "Incomplete. You need to include the verb and object, e.g., '你為什麼不想吃？'"
        }
      ],
      "incorrect_examples": [
        {
          "text": "你為什麼？",
          "error": "Missing the action. Add the verb and object."
        }
      ],
      "transformation_drills": ["Change '你為什麼不想吃？' to a statement: '因為我不餓。'"],
      "production_drills": ["Ask a friend why they don't want to go to the night market."],
      "common_error_patterns": ["Using '為什麼' without a verb", "Placing '為什麼' at the end of the sentence"],
      "repair_feedback": {
        "word_order": "Put '為什麼' at the start, then subject, then verb.",
        "politeness": "Add '請問' to make it more polite: '請問你為什麼不想吃？'",
        "vocabulary": "Use verbs like 想, 要, 喜歡."
      }
    },
    {
      "pattern": "subject + 因為 + reason，所以 + result",
      "structure": ["subject", "因為", "reason", "，", "所以", "result"],
      "explanation_en": "This is a variation of the 因為...所以... structure where the subject is placed before '因為'. It emphasizes the subject who has the reason.",
      "title": "Subject + 因為...所以... (Emphasizing the Subject)",
      "meaning": "Subject, because of reason, therefore result",
      "when_to_use": ["When you want to emphasize who is giving the reason", "When comparing different people's reasons"],
      "when_not_to_use": ["When the subject is obvious from context", "In very short sentences where the subject is not needed"],
      "pragmatic_notes": "In Taiwan, this structure is common when contrasting reasons between people, e.g., '我因為太累了，所以不想去，他因為有空，所以想去。'",
      "word_order_notes": "The subject comes before '因為'. This is different from the basic structure where '因為' starts the sentence.",
      "english_contrast": "In English, you can say 'I don't want to go because I'm tired.' In Chinese, the subject must be before '因為': '我因為太累了，所以不想去。'",
      "korean_contrast": "In Korean, the subject is marked with '은/는' and can come before the reason clause. In Chinese, the subject is placed before '因為'.",
      "negative_examples": [
        {
          "text": "因為我太累了所以不想去。",
          "error": "This is correct but doesn't emphasize the subject. If you want to emphasize '我', put it before '因為'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我所以不想去因為太累了。",
          "error": "Wrong word order. Use '我因為太累了，所以不想去。'"
        }
      ],
      "transformation_drills": ["Change '因為我沒時間，所以不去。' to emphasize the subject: '我因為沒時間，所以不去。'"],
      "production_drills": ["Explain why you want to stay home today, emphasizing yourself as the subject."],
      "common_error_patterns": ["Placing '所以' before the reason", "Omitting the subject when it's needed for contrast"],
      "repair_feedback": {
        "word_order": "Subject first, then 因為, then reason, then 所以, then result.",
        "politeness": "This structure is neutral and polite.",
        "vocabulary": "Use reason words like 生病, 感冒, 頭痛, 沒睡飽."
      }
    }
  ]
}
